  const ayahs: AyahProps[] = [
    { ayahId: 114, surahNumber: 2, pageNumber: 17, isComplete: true, continuesFromPrev: true, textData: "سُئِلَ مُوسۭيٰ مِن قَبْلُؐ وَمَنْ يَّتَبَدَّلِ ۱لْكُفْرَ بِالِايمَـٰنِ فَقَد ضَّلَّ سَوَآءَ ۰لسَّبِيلِؐ" },
    { ayahId: 115, surahNumber: 2, pageNumber: 17, isComplete: true, continuesFromPrev: false, textData: "وَدَّ كَثِيرٌ مِّنَ اَهْلِ ۱لْكِتَــٰــبِ لَوْ يَرُدُّونَكُم مِّنۢ بَعْدِ إِيمَــٰنِكُمْ كُفَّاراٗؐ حَسَداً مِّنْ عِندِ أَنفُسِهِم مِّنۢ بَعْدِ مَا تَبَيَّنَ لَهُمُ ۴لْحَقُّؐ فَاعْفُواْ وَاصْفَحُواْ حَتَّيٰ يَاتِيَ ۰للَّهُ بِأَمْرۣهِؐ“ إِنَّ ۰للَّهَ عَلَيٰ كُلِّ شَيْءٍ قَدِيرٌؐ" },
    { ayahId: 116, surahNumber: 2, pageNumber: 17, isComplete: true, continuesFromPrev: false, textData: "وَأَقِيمُواْ ۴لصَّلَوٰةَ وَءَاتُواْ ۴لزَّكَوٰةَؐ وَمَا تُقَدِّمُواْ لَأِنفُسِكُم مِّنْ خَيْرٍ تَجِدُوهُ عِندَ ۰للَّهِؐ إِنَّ ۰للَّهَ بِمَا تَعْمَلُونَ بَصِيرٌؐ" },
    { ayahId: 117, surahNumber: 2, pageNumber: 17, isComplete: true, continuesFromPrev: false, textData: "وَقَالُواْ لَنْ يَّدْخُلَ ۰لْجَنَّةَ إِلاَّ مَن كَانَ هُوداٗ اَوْ نَصَـٰرۭيٰؐ تِلْكَ أَمَانِيُّهُمْؐ قُلْ هَاتُواْ بُرْهَــٰنَكُمُ; إِن كُنتُمْ صَـٰدِقِينَؐ" },
    { ayahId: 118, surahNumber: 2, pageNumber: 17, isComplete: true, continuesFromPrev: false, textData: "بَلۭيٰ مَنَ اَسْلَمَ وَجْهَهُ„ لِلهِ وَهُوَ مُحْسِنٌ فَلَهُ; أَجْرُهُ„ عِندَ رَبِّهِ” وَلاَ خَوْف٘ عَلَيْهِمْ وَلاَ هُمْ يَحْزَنُونَؐ" },
    { ayahId: 119, surahNumber: 2, pageNumber: 17, isComplete: true, continuesFromPrev: false, textData: "وَقَالَــتِ ۱لْيَهُودُ لَيْسَــتِ ۱لنَّصَـٰرۭيٰ عَلَيٰ شَيْءٍ وَقَالَــتِ ۱لنَّصَـٰرۭيٰ لَيْسَــتِ ۱لْيَهُودُ عَلَيٰ شَيْءٍ وَهُمْ يَتْلُونَ ۰لْكِتَــٰــبَؐ كَذَ؛لِكَ قَالَ ۰لذِينَ لاَ يَعْلَمُونَ مِثْلَ قَوْلِهِمْؐ فَاللَّهُ يَحْكُمُ بَيْنَهُمْ يَوْمَ ۰لْقِيَــٰمَةِ فِيمَا كَانُواْ فِيهِ يَخْتَلِفُونَؐ ®" },
    { ayahId: 120, surahNumber: 2, pageNumber: 17, isComplete: false, continuesFromPrev: false, textData: "وَمَنَ اَظْلَمُ مِمَّن مَّنَعَ مَسَـٰجِدَ ۰للَّهِ أَنْ يُّذْكَرَ" }
  ];

